public static async getDomainAccountByAccountName(search: string): Promise<DomainAccountInfo> {
  let domainAccountMap: Map<string, DomainAccountInfo> | undefined =
    AppStorage.get(AppStorageConstant.DOMAIN_ACCOUNT_MAP);
  let domainAccount: DomainAccountInfo | undefined = domainAccountMap?.get(search.toLocaleUpperCase());
  if (domainAccount) {
    return domainAccount;
  }
  let domainResponse: DomainAccountResponse | undefined =
    await AccountManager.getDomainAccountWithRetry([search]);
  if (domainResponse && domainResponse.getData() && domainResponse.getData().length > 0) {
    return domainResponse.getData()[0];
  }
  return new DomainAccountInfo();
}

public async getAuthorizedAccount(): Promise<string[]> {
  HiLog.info(TAG, 'Enter getAuthorizedAccount.');
  let accountInfo: osAccount.OsAccountInfo | null = null;
  try {
    accountInfo = await getOsAccountInfo();
  } catch (err) {
    HiLog.wrapError(TAG, err, 'getOsAccountInfo failed');
    return [];
  }
  const ownerAccountId: string = accountInfo.distributedInfo.name;
  const associationMgr: AccountAssociationManager | null = AccountAssociationManager.getInstance();
  if (!associationMgr) {
    HiLog.error(TAG, 'Get account association manager failed.');
    return [];
  }
  const authorizedAccounts: AuthorizedAccount[] = await associationMgr.getAuthorizedAccount(ownerAccountId);
  let responseData: string[] = [];
  authorizedAccounts.forEach(account => {
    responseData.push(account.getUserAccount());
  });
  return responseData;
}

async function getUserId(): Promise<number> {
